INSERT INTO notes VALUES('23ad3fbd-7fa9-4022-9918-90a936e382c2','',replace('Microsoft Azure DevOps Pipelines is a cloud-based service that automates the process of building, testing, and deploying code. It''s part of the Azure DevOps platform. [1, 2, 3]  \nFeatures [3]  \n\n• Continuous integration, testing, and delivery: Azure Pipelines combines these three processes to build, test, and deliver code to any destination. [3]  \n• Supports many languages and project types: Azure Pipelines supports all major languages and project types. [3]  \n• Built-in security and compliance: Azure Pipelines has built-in security and compliance features. [4]  \n• Flexible pricing: Azure Pipelines offers flexible pricing plans, including free open-source projects, Microsoft-hosted CI/CD, and self-hosted CI/CD. [5]  \n\nHow to use Azure Pipelines [6]  \n\n• Create a pipeline in the Azure DevOps web portal using the Classic user interface editor. \n• Define a pipeline to build, test, and publish your artifact (binary). \n• Define a release pipeline to consume your binary and deploy it to specific targets. \n\nBenefits [2]  \n\n• Azure Pipelines simplifies and streamlines the process of building and deploying applications. \n• It makes it easier for teams to collaborate and deliver code efficiently. \n\n\nGenerative AI is experimental.\n\n[1] https://www.xmatters.com/integration/azure-devops-pipeline[2] https://www.xenonstack.com/blog/microsoft-azure-devops-pipeline[3] https://learn.microsoft.com/en-us/azure/devops/pipelines/get-started/what-is-azure-pipelines?view=azure-devops[4] https://azure.microsoft.com/en-gb/products/devops/pipelines[5] https://azure.microsoft.com/en-us/products/devops/pipelines[6] https://learn.microsoft.com/en-us/azure/devops/pipelines/get-started/pipelines-get-started?view=azure-devops\nNot all images can be exported from Search.\n','\n',char(10)),'2025-01-31 11:58:18',NULL,'');
