INSERT INTO notes VALUES('bbe5e5be-5e14-47f9-89d6-a3f82cb2ed2e','',replace('Step Three Load the 2D Array\n\nFill in the method saveToMultidimensionalArray Look at the notes in the method to see the specifics.\n\nCreate a nested loop to loop to add items to the array.\n\nString dataray new String[row][columns];\n\nHere are some tips\n\ncount-Your multidimensional array will have rows, where is the number of lines in the file. You should count the\n\nnumber of lines inside the program-don''t hardcode it!\n\ncolumn count-The number of columns is how many pieces of data are within the commas in each line. Look at the first row the file and count the pieces of data. You can hardcode the number of columns\n\nWarning some rows in the CSV file might vary in tength For example, if the first row has 3 pleces of data, other rows might be missing data (only 2 values) or have too much (4 values). While this isn''t good, it happens in CSV files all the time. Here''s how to handle this in the assignment-','\n',char(10)),'2023-04-04 11:09:19',NULL,'');
