INSERT INTO notes VALUES('56d5639a-7661-41be-b572-e9b3d190f06e','',replace('Question 11\n\n* What is the value stored in "sentence" after the function is run with\n\nquesti\n\n* fnane tracing.txt" (the input file)?!!\n\nQuestion: 21\n\nSuppose you replace Line 11 of the function with:\n\nN If word es "hello"\n\nxa. Does the function output the same result us before! Quest 2a-\n\nExpress your answer as "yes" or "no")\n\nXh. Will the function error at any point? If not, your answer should be -2, otherwise it should be the wordCount for which it might error.\n\nquest2b-\n\nQuestion 3:\n\nSuppose you duplicate Line 17 so that now there are two lines back to back that are string fgeti(infile).\n\nWhat would be the value stored in sentence after the\n\nfunction is run with frame tracing.txt?\n\nquest3-\n\nQuestion 4:\n\nSuppose your input file contains the following text instead:\n\nhello, world, Hello, universe hello, Galaxy, hello,planet\n\nWhich of the following replacements for Line 11 would lead to the same result as the original function\n\nSELECT ALL THAT APPLY\n\nA: If lower (word) "hello";','\n',char(10)),'2023-04-06 03:14:35',NULL,'');
