INSERT INTO notes VALUES('66c5e33f-469e-42bb-908c-0a4b865ece2c','',replace('class Solution:\n    def removeNthFromEnd(self, head: ListNode, n: int) -> ListNode:\n        dummy = ListNode(0, head)\n        left = dummy\n        right = head\n\n        while n > 0:\n            right = right.next\n            n -= 1\n\n        while right:\n            left = left.next\n            right = right.next\n\n        # delete\n        left.next = left.next.next\n        return dummy.next','\n',char(10)),'2024-04-03 20:50:53',NULL,'');
