INSERT INTO notes VALUES('aba1128a-e2b9-4ead-99bc-ce820a47220e','Coursera Courses',replace('Mastering AI\n1. https://in.coursera.org/specializations/machine-learning-introduction\n2. https://in.coursera.org/specializations/deep-learning\n3. https://in.coursera.org/specializations/firstprinciplesofcomputervision\n4. https://in.coursera.org/specializations/natural-language-processing\n5. https://in.coursera.org/specializations/generative-adversarial-networks-gans?=\n6. https://in.coursera.org/specializations/practical-data-science#courses\n    (AutoML and AWS)\n\n(Above all applied)\n\nDeep Learning.AI Slides\nhttps://www.deeplearning.ai/resources/#ai-notes\n\nDeep Neural Networks with Pytorch \nhttps://www.coursera.org/professional-certificates/ai-engineer#courses\nhttps://www.coursera.org/learn/deep-neural-networks-with-pytorch#syllabus\n\n(above all applied)\n\nComputer Vision by Mathworks (not applied)\nhttps://www.coursera.org/specializations/image-processing#courses\nhttps://in.coursera.org/specializations/computer-vision\n\nC and C++ (not applied)\nhttps://www.coursera.org/specializations/coding-for-everyone#courses\n\nProgramming Foundations with JavaScript, HTML ,CSS (not applied)\nhttps://www.coursera.org/learn/duke-programming-web?specialization=java-programming\n\nJava Programming (not applied)\nhttps://www.coursera.org/specializations/object-oriented-programming#courses\n\nData Science (to be applied)\n\nhttps://in.coursera.org/professional-certificates/ibm-data-science\n\nMLOps (Enrolled)\nhttps://in.coursera.org/specializations/machine-learning-engineering-for-production-mlops#courses\n\nAI for Good\nhttps://www.coursera.org/specializations/ai-for-good#courses\n\nGPU Programming\nhttps://in.coursera.org/specializations/gpu-programming\n\nComputer Architecture (free)\nhttps://in.coursera.org/learn/comparch#syllabus\n\nComputer Science Algorithms, Theory and Machines (free)\nhttps://in.coursera.org/learn/cs-algorithms-theory-machines#syllabus\n\nMathemati