INSERT INTO notes VALUES('54ddc640-c001-44c6-824a-4d6d7c67b5dc','Variance Calculation',replace('https://www.cuemath.com/sample-variance-formula/\n\nDecision trees reduction in variance calculation\nhttps://in.coursera.org/learn/advanced-learning-algorithms/lecture/XlM5n/regression-trees-optional\n\nRegression trees\n\nchoose the feature with largest reduction in variance in regression based problems\nearlier we choose the feature with largest reduction in Information gain in classification based problems\n########Program for variance in python#####\n# define the list of numbers\nnumbers = [7.2, 9.2, 8.4, 7.6, 10.2, 8.8, 15, 11, 18, 20]\n\n# calculate the mean\nmean = sum(numbers) / len(numbers)\n\n# calculate the sum of squared differences from the mean\nsquared_differences_sum = sum((x - mean)**2 for x in numbers)\n\n# calculate the variance\nvariance = squared_differences_sum / (len(numbers)-1)\n\n# output the result\nprint("The variance is:", variance)\n######################end###############','\n',char(10)),'2023-03-16 13:54:40',NULL,'');
