INSERT INTO notes VALUES('6846b6cc-c115-4666-94d3-0dc89483d1e5','',replace('ఆర్ సి సి బిల్డింగ్ లేబర్ కాంట్రాక్టు అగ్రిమెంట్\n\n36:09-02-2025\n\nవ్రాయించుకొన్నవారు: తిరుపతి జిల్లా తిరుపతి అర్బన్ మండలం, తిరుపతి టౌన్,\n\nS.T.V. నగర్, K.R.R. కాలనీ, రోడ్ నెం.2, డోర్ నెం. 19-4-3H/14A గల ఇంటిలో కాపురం యుండు కలత్తూరు రాజారెడ్డి గారి భార్య కలత్తూరు సరస్వతి (ఆధార్ నెం. 7527. 3038 42211-12 వారు ఓర గారికి..\n\nవ్రాయించియిచ్చువారు, తిరుపతి జిల్లా, తిరుపతి రూరల్ మండలం, మట్టుగుంట, విజయ నగర్ కాలనీ లో ఇంటిలో కపురముండు పెద్ద బ్రహమయ్య గారి కుమారుడు బి విజయ కుమార్ (ఆధార్ నెం.9923 9843 1845)-2వ వారు బిల్డింగ్ లేటర్ కాంట్రాక్ట్ సంబందించి వ్రాయించియిచ్చిన ఆర్.సి.సి. బిల్డింగ్ గ్రౌండ్ ఫ్లోర్, 1 & 2nd ఫ్లోర్ డూప్లెక్స్ బిల్డింగ్ అగ్రిమెంట్ ఏమనగా!\n\nK.Saraswathi\n\n1 వ వారు (ఓనరు)\n\n2. వారు (మేస్త్రి)\n\n\n\n\nమనలో 1వ వారికి సర్వ హక్కులు కలిగి స్వాధీనానుభవనములో ఉండు తిరుపతి జిల్లా తిరుపతి రూరల్ మండలం, అవిలాల, గణేష్ నగర్ ఏరియా లో తూర్పు పడమర 50 అడుగులు, 6 2 36 , 1800 2 000 пеш 200 по ພ. 2 20.475/24, 475/21. 475/23, 475/2k, 475/21, 0 2 200 50 అంకణములు ఆర్. సి. సి. గ్రౌండ్, ఫస్ట్ ఫ్లోర్, సెకండ్ ఫ్లోర్, డూప్లెక్సీ బిల్డింగ్ కట్టించి ఇస్తున్నాను. దీంట్లో 131 అంకణము మాత్రమే మూడు ఫ్లోర్ కలిపి గ్రౌండ్ ఫ్లోర్ కి 43.68 అంకణాలు 1st ఫ్లోర్ కి 43.68 అంకణాలు, సికండ్ ఫ్లోర్ కి 43.68 అంకణాలు, 1 అంకాణానికి 15,000/- అక్షరాల పదివ్రాను వేలు రూపాయలు ప్రకారం మన ఇరువురం ఒప్పందము కుదుర్చుకొని ఇందుకు గాను ఈ దినము అడ్వాన్స్ గా 1,00,000/- అక్షరాల ఒక లక్ష రూపాయలు 1వ వారు 2వ వారికి చెల్లించడమైనది.\n\nలేబర్ కాంట్రాక్ట్ మేస్తి చేయవలసిన పనులను,\n\n1) పిల్లర్స్ గుంతలు, పుటింగ్స్, కాలమ్స్, టెడ్ కాంక్రీట్.\n\n2) గోడలు కట్టుట, ప్లాస్టింగ్.\n\n3) ວັງ 14 (2)\n\n4) ప్లింత్ బీమ్\n\n5) సంపు, సెప్టిక్ ట్యాంక్.\n\n6) బేస్ మట్టం రోడ్డు కు తగనట్టు అడుగులు ఎత్తు వరకు.\n\n7) బేస్ మట్టం మొత్తానికి టెడ్ చేయవలెను.\n\n8) పారపీట్ వాల్, మిద్దెపైన పోరింగ్.\n\n9) సెంట్రీగ్ పనులు మొత్తము చేసిస్తాను, సెంట్రిగ్ వర్క్ మొల్డింగ్ రాడ్ పిడతాను.\n\n10) మైయీన్ చాలబందరము, కటులు, అన్నిటిని గోడకు అమర్చవలెను.\n\n11) లోపల, బయిట ప్లాస్టింగ్ చేయవలెను.\n\n12) ఎలివేషన్, స్టెర్ కేస్, మెట్లు కట్టవలెను, డూప్లెక్స్ మెట్లు మరియు స్టీర్ కేన్ కట్టవలెను.\n\n13) లిఫ్ట్ కట్టవలెను, లిస్ట్ ప్లాస్టింగ్ పనులు చేసిస్తాను.\n\nK Sarswathi\n\nsvishy\n\n1 వ వారు (ఓనరు)\n\n2/4\n\n2వ వారు (మేస్డ్)\n\n\n14) పోకేష్ డిజైన్ లు, సెల్బు పెట్టవలెను.\n\n15) గ్రీల్స్ పెట్టవలసిన చోట పెట్టిస్తాను.\n\n16) తట్టలు, పాఠలు, దారాలు, జల్లెడ, కొయ్యలు, స్పంజలు, పొంకట్టలు, చిలబు, వస్ట్ ఆయిల్ ఈ మొత్తం నేనే తెచ్చుకొంటాను.\n\n17) బయిట, లోపాల, మెట్లకు, ప్లాస్టింగ్ చేసిస్తాను.\n\n18) ఇసుక, సిమెంట్, గుల్ల ఇంజనీరింగ్ ఇచ్చిన కొలత ప్రకారంగా కట్టిస్తాను.\n\n19) ఇంటి పనులు పూర్తి అయ్యి వరకు సిమెంట్ పని ఏదైనా ఉన్నచో మన్రోయే పూర్తి బాధ్యత నేనే వహిస్తాను. మరియు మీకు తగినట్టు పూర్తి పని చేసిస్తాను.\n\n20) ఈ రోజు 131 అంకణాలల లెక్కకు స్లాట్ 10 స్లాట్ అంకనాలికి 15,000/- తో చొప్పున ఏదైనా అంకణాలు మించితే, ఎలివేషన్ కాకుండా మిగితా అంకణాలకు 15,000/- రూయపాయలు మాత్రమే నేను తీసుకుంటాను.\n\n໐໖ 6 43.68\n\nRs.15,000,00/-\n\n0.6,55,200.00/-\n\n໑໘ 43.68 Rs.15.000.00/-\n\n0.6,55,200.00/-\n\n5 26 43.68+ Rs.15,000.00/-\n\nπ.6,55,200.00/-\n\nమేస్తే కీ పేమెంట్ ఇచ్చే విధానం\n\n1) టెసిమెంట్, కాంపౌండ్ తో కలిపి, వాటర్ సంప్, సెప్టిక్ ట్యాంక్\n\n3.2,00,000/-\n\n2) బ్రిక్ వర్క్ (కంప్లీట్) R.C.C. గ్రౌండ్ ఫ్లోర్ స్లాబ్ వర్క్\n\n→ 67.2.50,000/-\n\n3) ఫస్ట్ ఫ్లోర్, బ్రిక్ వర్క్ (కంప్లీట్) R.C.C. కాలమ్స్ (కంప్లీట్), స్టర్ కేసిస్ (2Nd''s ఇన్స్టిసైడ్ అండ్ ఔట్సైడ్)\n\n→02.00.000\n\n4) R.C.C. స్లాబ్ వర్క్ తో కలిపి సెంట్రింగ్ వర్క్ ఫస్ట్ ఫ్లోర్\n\n→6.2.50.03/4\n\n5) సెకండ్ ఫ్లోర్, బ్రిక్ వర్క్ (కంప్లీట్), R.C.C. కాలమ్స్ (కంప్లీట్), స్టైర్ కెసెస్ (2No''s ఇన్స్టిసైడ్ అండ్ ఔట్ సైడ్\n\n→0.2,00,000/-\n\n6) R.C.C. స్టాట్ వర్క్ తో కలిపి సెంట్రింగ్ వర్క్ సికండ్ ఫ్లోర్\n\n→ 2.2.50,000/-\n\nK Saraswathi 1 వ వారు (ఓనరు)\n\nBUDAY\n\n4\n\n7) గ్రౌండ్ ఫ్లోర్, ఫస్ట్ ఫ్లోర్, సెకండ్ ఫ్లోర్, ప్లాస్టింగ్ వర్క్ ఇనసైడ్ కలిపి కబోర్డ్స్\n\n1,50,000/-\n\n8) గ్రౌండ్ ఫ్లోర్, ఫస్ట్ ఫ్లోర్, సెకండ్ ఫ్లోర్, ప్లాస్టింగ్ వర్క్ ఔట్ సైడ్\n\n5.1,50,000/-\n\n9) ఎలివేషన్ & కాంపౌండ్ వర్క్\n\n→6.2,00,000/-\n\n10) లెఫ్ట్ ఓవర్ అమౌంట్\n\n6.1.15,615/\n\nటోటల్\n\n→19,65,615/-\n\nటెర్మ్స్ అండ్ కండిషన్స్\n\n1) రొక్కము అన్నీ పైన తెలిపిన షెడ్యూల్ ప్రకారం ఒనరు మేస్త్రి కి ఇవ్వవలెను.\n\n2) ఒనరు పేమెంట్ అలస్యం చేసినప్పుడు మేస్తే పని నిలిపివేయబడను.\n\n3) ఒనడు / ఇంజీనియర్, విని సంతృప్తి చందకు పోయినచో, ఆలస్యం చేసినచో మేస్త్రిని మార్చబడను.\n\nK Saraswathe\n\n1 వ వారు (ఓనరు)\n\nసాక్షాలు\n\n1.\n\n2','\n',char(10)),'2025-07-11 22:29:04',NULL,'');
