INSERT INTO notes VALUES('b5c530f1-b5f4-4b68-a654-bb5c5f82189b',replace('\nNeural networks compatability of vectors and produt input and in between layers','\n',char(10)),replace('input X\nweights(coefficients) W\nbias b\nWx+b ==> we need to calculate np.dot(w,x)+b\nx = bracket(1          w = bracket(1 3 5      b = bracket(1 1 1)\n                     2)                              2 4 6)\nx is 2 *1 matrix and w is 2*3 matrix \n\nHere columns are vectors means  1 2 is one vector as x1, 1 2 is one vector as w1 3 4 is another vector as w2 like that\nb is actually a scalar\nwe do transpose(x) *w + b = 1*2 matrix with 2*3 matrix + 1*3  matrix\n\n***********\nHere vectors size should be same means x has column vector of length 2 and w has the column vector of length 2.\nWhich in turn is the matrix multiplication property after taking one as transpose so that number of columns which is taken first in product = number of rows in second in product\nSo that we can take dot product of vectors\n\nFinal obtained matrix is as same number of rows as transpose(x) and same number of columns of w \n********\nFirst figure is based on vectorization using matmul and numpy where transpose is considered\n\nSecond figure is based on tensorflow where a_in is used and the transpose is not taken into consideration and individually we are performing.\n\nThere is a convention in TensorFlow that individual examples are actually laid out in rows in the matrix X rather than in the matrix X transpose which is why the code implementation actually looks like in TensorFlow 2nd figure. But in 1st figure explains why with just a few lines of code you can implement forward prop in the neural network and moreover, get a huge bonus because modern computers are very good at implementing matrix multiplications such as matmul efficiently. \n\nThis is the basic of vectorization of neural network.\nvectorization is very fast\n(This is the most important thing.)  ','\n',char(10)),'2023-02-25 01:01:29',NULL,'');
