INSERT INTO notes VALUES('714e02bd-2f59-45a2-97de-7c6bd92de3da','',replace('# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, x):\n#         self.val = x\n#         self.next = None\n\nclass Solution:\n    def detectCycle(self, head: Optional[ListNode]) -> Optional[ListNode]:\n        if not head or not head.next:\n            return None\n\n        slow = head\n        fast = head\n\n        # Find the intersection point of the two pointers\n        while fast and fast.next:\n            slow = slow.next\n            fast = fast.next.next\n            if slow == fast:\n                break\n        else:\n            # If there''s no cycle, return None\n            return None\n\n        # Move one pointer back to the head\n        slow = head\n\n        # Move both pointers at the same pace until they meet\n        while slow != fast:\n            slow = slow.next\n            fast = fast.next\n\n        # When they meet, it''s the start of the cycle\n        return slow\n','\n',char(10)),'2024-04-04 20:22:31',NULL,'');
