INSERT INTO notes VALUES('6ea9f622-230d-4629-beb1-91bed1cfb659','',replace('class Solution:\n    def createBinaryTree(self, descriptions: List[List[int]]) -> Optional[TreeNode]:\n        \n        tree = dict()\n        children = set()\n        for parent, child, isLeft in descriptions:\n            if parent not in tree : tree[parent] = TreeNode(parent)\n            if child not in tree : tree[child] = TreeNode(child)\n            \n            if isLeft : tree[parent].left = tree[child]\n            else : tree[parent].right = tree[child]\n        \n            children.add(child)\n        \n        for parent in tree:\n            if parent not in children:\n                return tree[parent]\n\n\n\n\nKth smallest element in BST\n            ','\n',char(10)),'2024-04-29 21:12:02',NULL,'');
