INSERT INTO notes VALUES('82835c14-c4fe-41cd-9fe9-a6c6c4dd27e7','',replace('https://github.com/zhouchong90/LeetCode-Python-Solution/blob/master/Solutions/31%20Next%20Permutation.py\n\nclass Solution:\n    def merge(self, intervals: List[List[int]]) -> List[List[int]]:\n       n = len(intervals)\n       intervals.sort()\n       a = intervals[0]\n\n       s = []\n\n       for i in range(n):\n            temp = intervals[i]\n            if temp[0]<=a[1]:\n                a[1]=max(temp[1],a[1])\n            else:\n                s.append(a)\n                a = temp\n       s.append(a)\n\n       return s','\n',char(10)),'2024-03-31 17:42:16',NULL,'');
