INSERT INTO notes VALUES('ef914bb2-f717-4ee0-96c4-7af47d1d73a8','Vigenere cipher',replace('// C++ code to implement Vigenere Cipher\012#include<bits/stdc++.h>\012using namespace std;\012 \012// This function generates the key in\012// a cyclic manner until it''s length isn''t\012// equal to the length of original text\012string generateKey(string str, string key)\012{\012    int x = str.size();\012 \012    for (int i = 0; ; i++)\012    {\012        if (x == i)\012            i = 0;\012        if (key.size() == str.size())\012            break;\012        key.push_back(key[i]);\012    }\012    return key;\012}\012 \012// This function returns the encrypted text\012// generated with the help of the key\012string cipherText(string str, string key)\012{\012    string cipher_text;\012 \012    for (int i = 0; i < str.size(); i++)\012    {\012        // converting in range 0-25\012        char x = (str[i] + key[i]) %26;\012 \012        // convert into alphabets(ASCII)\012        x += ''A'';\012 \012        cipher_text.push_back(x);\012    }\012    return cipher_text;\012}\012 \012// This function decrypts the encrypted text\012// and returns the original text\012string originalText(string cipher_text, string key)\012{\012    string orig_text;\012 \012    for (int i = 0 ; i < cipher_text.size(); i++)\012    {\012        // converting in range 0-25\012        char x = (cipher_text[i] - key[i] + 26) %26;\012 \012        // convert into alphabets(ASCII)\012        x += ''A'';\012        orig_text.push_back(x);\012    }\012    return orig_text;\012}\012 \012// Driver program to test the above function\012int main()\012{\012    string str = "TINY";\012    string keyword = "YANS";\012 \012    string key = generateKey(str, keyword);\012    string cipher_text = cipherText(str, key);\012 \012    cout << "Ciphertext : "\012         << cipher_text << "\n";\012 \012    cout << "Original/Decrypted Text : "\012         << originalText(cipher_text, key);\012    return 0;\012}\012/*\012Ciphertext : RIAQ\012Original/Decrypted Text : TINY\012*/','\012',char(10)),'2023-02-13 15:59:51',NULL,'');
