INSERT INTO notes VALUES('45d925d7-ba0f-4655-b404-ee96331135ef','',replace('Coming to Lumenci  Lumenci specializes Innovation value creation and it is broadly divided into 3 technology groups software technology group,Telecom & wireless Technology group and semiconductor technology group and Lumenci is the  industry''s most strategic patent monetization partner. works with the world''s top technology companies, law firms, inventors, and start-ups to find the value in their inventions and help them pursue and defend that value throughout the ideation to monetization lifecycle. It help clients convert innovation into patent portfolios and identify their best monetization opportunities and works with wide variety of technologies including software, semiconductors, telecom, networking, and biotech technologies. Lumenci combines technology domain expertise with strategic industry connections to guide the best route to ROI. \n\nIntellectual Property, Source Code Reviews, Reverse Engineering, Product Testing, Strategy Consulting, Technology Research Reports, Infringement Analysis, Validity Analysis, Portfolio Analysis, End- to-End Litigation Consulting. Wireless Networks, Telecommunications, Enterprise Software, Software Asset License Management, Mobile Devices and Processors, Deposition and Trial Support, Trade Secrets, Damages Evaluation, Semiconductors, Patent Licensing, Biomedical, and Blockchain\n','\n',char(10)),'2022-12-15 01:00:53',NULL,'');
