INSERT INTO notes VALUES('622255f0-b381-451b-bd3d-e8a465178c77','Overloading extraction and insertion operation c++',replace('#include<iostream>\n\nclass Point {\npublic:\n    int x, y, z;\n\n    friend std::ostream& operator<<(std::ostream& os, const Point& point) {\n        return os << point.x << " " << point.y << " " << point.z;\n    }\n\n    friend std::istream& operator>>(std::istream& is, Point& point) {\n        return is >> point.x >> point.y >> point.z;\n    }\n};\n\nclass Rectangle {\npublic:\n    int length, breadth;\n\n    friend std::ostream& operator<<(std::ostream& os, const Rectangle& rect) {\n        return os << rect.length << " " << rect.breadth;\n    }\n\n    friend std::istream& operator>>(std::istream& is, Rectangle& rect) {\n        return is >> rect.length >> rect.breadth;\n    }\n};\n\nclass Triangle {\npublic:\n    int base, height;\n\n    friend std::ostream& operator<<(std::ostream& os, const Triangle& triangle) {\n        return os << triangle.base << " " << triangle.height;\n    }\n\n    friend std::istream& operator>>(std::istream& is, Triangle& triangle) {\n        return is >> triangle.base >> triangle.height;\n    }\n};\n\nint main() {\n    Point p;\n    Triangle t;\n    Rectangle r;\n\n    std::cin >> p;\n    std::cin >> t;\n    std::cin >> r;\n\n    std::cout << p << " " << t << " " << r << std::endl;\n\n    std::cin >> p;\n    std::cin >> r;\n    std::cin >> t;\n\n    std::cout << p << " " << t << " " << r << std::endl;\n\n    std::cin >> r;\n    std::cin >> t;\n    std::cin >> p;\n\n    std::cout << r << " " << t << " " << p << std::endl;\n\n    std::cin >> r;\n    std::cin >> p;\n    std::cin >> t;\n\n    std::cout << r << " " << p << " " << t << std::endl;\n\n    std::cin >> t;\n    std::cin >> r;\n    std::cin >> p;\n\n    std::cout << t << " " << r << " " << p << std::endl;\n\n    std::cin >> t;\n    std::cin >> p;\n    std::cin >> r;\n\n    std::cout << t << " " << p << " " << r << std::endl;\n\n    return 0;\n}','\n',char(10)),'2024-01-18 14:40:27',NULL,'');
