INSERT INTO notes VALUES('367b8e39-2099-47d4-8af5-a0dbdedb1fd3','Logits',replace('Logits make accurate values so we generally prefer logits not to round off\n\nIn case of logistic regression using of logits or not make that much matter but in sofmax regression more accurate values required so we use logits to avoid numerical round off errors\n\nIf z is very small e^z becomes much more smaller makes some of the calculations diminish and If z is very large e^z becomes much more larger makes some of the calculations explode. This occurs due to intermediate calculations. We use logits to avoid this\n\nUsing logits make numerically accurate values. Here logarithms are there \nlogit(p)=log(p/(1-p))\n\nLogits is recommended it makes numerically stable ','\n',char(10)),'2023-03-01 02:37:51',NULL,'');
