INSERT INTO notes VALUES('01824648-cc6e-4ecf-a5e0-f93458ba8383','',replace('For this lab, complete the main, bubbleSort, and selectionSort functions in the template file. This program should create two identical arrays of random numbers, and then sort each one using a different sorting algorithm. Your program should then keep track of how long the sorting algorithm takes to complete, and show the results.\n\n The instructions for the main function are given as comments in the template file. You can find the bubble sort and selection sort algorithms in the textbook or in the programs from the lab assignment for this week. \n \nUse the ARRAY_LENGTH constant whenever you need the length of the arrays. You can change the value of ARRAY_LENGTH as needed. \n\nI''ve provided some additional functions in the template file to make it easier for you to complete this assignment: -randomFillArray(int theArray[], int arrayLength) : fills an array with random integers.The arguments are the array itself and the length of the array.\n - startTimer() : starts the timer. Call this function right before you perform the sorting algorithms. \n - endTimer() : ends the timer. Call this function right after you perform the sorting algorithms. This function returns the amount of time that has passed since startTimer() was called in milliseconds.\n  - printArray(int theArray[], int arrayLength) : prints the contents of its array argument. You can use this to check if your sorting algorithms are working correctly. This should only be used for your own testing purposes and is not required in the final program. \n \nTo use the timer functions, you just have to call them before and after you call the sorting functions. In the example below, the variable "bubbleTime" will store the amount of time the bubbleSort function took.\n\n startTimer (); \n bubbleSort (myArray, ARRAY LENGTH):\n int bubbleTime = endTimer();\n\nWhen you have completed the program, run the program with an array length of 20,000 . Submit a screenshot of this output along with the program file.\n\nThe exact amount of time the algorithms will vary each time it is run. It depends on the random values in the array, and the speed of your computer. For my computer, bubble sort took about 900 milliseconds on average, and selection sort took about 300 milliseconds on average (for array length of 20,000).\n\nTemplate code:\n\n#include <iostream>\n#include <cstdlib>\n#include <ctime>\n#include <iomanip>\n#include <chrono>\nusing namespace std;\n\n// the sort functions (fill these out below)\nvoid bubbleSort(int[], int);\nvoid selectionSort(int[], int);\n\n// the provided helper functions\nvoid randomFillArray(int[], int);\nvoid startTimer();\nint endTimer();\nvoid printArray(int[], int);\n\nchrono::time_point<chrono::high_resolution_clock> startTime;\n\n\n// The length of the arrays - change this as needed\nconst int ARRAY_LENGTH = 100;\n\n\nint main() {\n// COMPLETE THIS FUNCTION''S CODE\n// Print your name\n// Create one array\n// Fill the array with random numbers\n// Make an exact copy of the array\n// Sort one of the arrays using bubble sort and keep track of how long it took\n// Sort the other array using selection sort and keep track of how long it took\n// Output the results\nreturn 0;\n}\n\n// sorts the array argument using the bubble sort algorithm\nvoid bubbleSort(int theArray[], int arrayLength) {\n// COMPLETE THIS FUNCTION''S CODE\n}\n\n// sorts the array argument using the selection sort algorithm\nvoid selectionSort(int theArray[], int arrayLength) {\n// COMPLETE THIS FUNCTION''S CODE\n}\n\n/**\n* Helper functions:\n* You may use any of the functions below in your program\n* You do not need to make any changes to the helper functions\n*/\n\n// fills an array with random integers\nvoid randomFillArray(int theArray[], int arrayLength) {\n// sets the random number seed\nsrand(time(0));\n\n// fills the array with randomly generated numbers\nfor (int i = 0; i < arrayLength; i++) {\ntheArray[i] = rand();\n}\n}\n\n// sets the beginning point for the timer\nvoid startTimer() {\nstartTime = chrono::high_resolution_clock::now();\n}\n\n// returns how much time has passed since the timer was started in milliseconds (1000 milliseconds == 1 second)\nint endTimer() {\nchrono::time_point<chrono::high_resolution_clock> endTime = chrono::high_resolution_clock::now();\nauto duration = chrono::duration_cast<chrono::milliseconds>(endTime - startTime);\nreturn duration.count();\n}\n\n/**\n* prints the array in 10 columns\n*\n* WARNING: printing an array is very slow for long arrays (over 100 values)\n* Only use this function during testing if you need to see what is in your array\n*/\nvoid printArray(int theArray[], int arrayLength) {\ncout << "The array contains the values: " << endl;\nint count = 0;\nfor (int i = 0; i < arrayLength; i++) {\ncout << left << setw(7) << theArray[i];\ncount++;\nif (count == 10) {\ncout << endl;\ncount = 0;\n}\n}\ncout << endl << endl;\n}','\n',char(10)),'2023-04-05 09:29:59',NULL,'');
