INSERT INTO notes VALUES('250fc9a6-e07b-4165-83ea-632305fae057','Difference between is and == in python',replace('\nThe keyword is checks whether the variables are referring to the same object or not. If they are referring to the same object, then they have the same id otherwise they will have different id''s.\n\nWhereas, the == operator compares the values while checking whether they are referring to the same object or not.\n\n\nhttps://www.studytonight.com/post/difference-between-is-and-in-python\n\n\n''is'' refers if the variable is referring to the same variable location means IDs are also same then it will otherwise returns false. Then returns true otherwise returns false.\n\n''is'' generally used for Boolean values(true, false) and none and for rest we won''t use the ''is''. Because ''is'' is the strong equality than ''==''. ''=='' is mathematically equal to with potential conversion. ''is'' is the stronger thing.','\n',char(10)),'2023-03-17 02:14:41',NULL,'');
