INSERT INTO notes VALUES('911c56ab-0e3a-4e5f-8b21-a7bed70e1f16','',replace('Assume we sample three datasets as the following: \n\nD1\nX1	X2	label\n0.2	0.8	-1\n-0.9	0.9	1\n-0.8	0.	1\n0.2	-1.1	-1\n-0.4	-0.5	-1\n\nD2\nX1	X2	label\n1.1	0.7	-1\n-1.	1.1	1\n-0.7	-0.3	-1\n-1.	-1.1	-1\n-1.	0.3	1\n\nD3\nX1	X2	label\n-1.1	1.0	1\n-0.1	0.7	1\n0.2	-1.1	-1\n0.7	0.5	1\n-0.6	0.5	1\n\nTrain a model for each dataset using logistic regression. You can use the Sklearn code:\nfrom sklearn. linear_model import LogisticRegression \nmodel = LogisticRegression(random_state=0).fit (d1_x, d1_y) \nprint ("W = ", model.coef_) \nprint("b = ", model.intercept_) \nCalculate the average bias and variance for the trained logistic regression models given the following dataset. issume the optimal classifier perfectly predicts the correct labels. Show your work. Hint: Use Monte Carlo ategration for approximating the expectation.\n\nX1	       X2	  label\n1.01	-0.8	      -1\n0.24	0.33	1\n0.46	0.33	1\n-0.56	-0.31	-1\n-0.34	0.64	-1\n\n','\n',char(10)),'2023-03-28 00:33:44',NULL,'');
