INSERT INTO notes VALUES('0ffed7a2-6edf-4f4f-ae0c-2cdc8d939b45','',replace('class ListNode:\n    def __init__(self, val=0, next=None):\n        self.val = val\n        self.next = next\n\nclass Solution:\n    def swapPairs(self, head):\n        # If the list is empty or has only one node, no need to swap\n        if not head or not head.next:\n            return head\n\n        # Create a dummy node to facilitate swapping\n        dummy = ListNode(0)\n        dummy.next = head\n        prev_node = dummy\n\n        while prev_node.next and prev_node.next.next:\n            first_node = prev_node.next\n            second_node = prev_node.next.next\n\n            # Swapping nodes\n            prev_node.next = second_node\n            first_node.next = second_node.next\n            second_node.next = first_node\n\n            # Move prev_node to the next pair\n            prev_node = first_node\n\n        return dummy.next','\n',char(10)),'2024-04-04 21:05:37',NULL,'');
