INSERT INTO notes VALUES('bde77462-c355-4a8e-8a09-06b8c98c0558','Hacker rank study library ',replace('#include <iostream>\n#include <queue>\n\nusing namespace std;\n\nlong getMaximumScore(int arr[], int k, int n) {\n    priority_queue<int, vector<int>, greater<int>> minHeap;\n\n    // Initialize the heap with the first k elements\n    for (int i = 0; i < k; i++) {\n        minHeap.push(arr[i]);\n    }\n\n    // Process the remaining elements in the array\n    for (int i = k; i < n; i++) {\n        if (arr[i] > minHeap.top()) {\n            minHeap.pop();\n            minHeap.push(arr[i]);\n        }\n    }\n\n    // Calculate the sum of elements in the heap\n    long sum = 0;\n    while (!minHeap.empty()) {\n        sum += minHeap.top();\n        minHeap.pop();\n    }\n\n    return sum;\n}\n\nint main() {\n    int n, k;\n\n    cin >> n;\n\n    int arr[n];\n    for (int i = 0; i < n; i++)\n        cin >> arr[i];\n\n    cin >> k;\n\n    cout << getMaximumScore(arr, k, n);\n\n    return 0;\n}','\n',char(10)),'2024-01-18 13:34:13',NULL,'');
