INSERT INTO notes VALUES('63deef49-0ca5-4e89-8d08-d2f5ea3e1211','',replace('\nDLOps GPU Login Credentials\nDear ,\n\nHere are your HPC access credentials \n\nThe attached files will guide on how to access the GPU and run your codes. Please note the below three points\n\n1. You compulsorily need to change your password. To change the password, type the command - "passwd" without the quotes. Enter your current password and the new password. This will update all the authentication tokens.\n\n2. You can submit your jobs only on the "gpu" partition. When you type in the command - "squeue" without the quotes, you will be able to see all the partitions Le. gpu, small, test. The codes need to be submitted only on the "gpu" partition.\n\n3. You need to put your data inside the below mentioned path only-"/scratch/data/your-user- name". Replace your-user-name with the given username. You can access your data from there.\n\nNOTE - If you run the code when the deadline is near, you will not be able to finish it because the majority of students will schedule their jobs then. It is advisable that you start working on the assignment as soon as it is posted. The jobs are run sequentially and it might take some time. Please be patient.\n\nThanks,\nKishore Kumar','\n',char(10)),'2023-03-21 02:10:32',NULL,'');
