INSERT INTO notes VALUES('b6d4b65b-523c-47ae-8c6a-2f271debd007','Web page about me info add a section and add these details',replace('I am a Computer Vision and Machine Learning Engineer with a Master''s degree in Artificial Intelligence from the Indian Institute of Technology Jodhpur.\nWith industry experience as a Technical Lead at HCLTech and prior work at TCS, I specialize in developing scalable AI solutions across 3D reconstruction, generative modeling, and real-time image and video processing. My recent work includes building a 3D scene reconstruction pipeline using NeRF and COLMAP, optimizing deep learning models for edge deployment with OpenVINO, and implementing diffusion-based image synthesis with ControlNets. I have explored Retrieval-Augmented Generation (RAG) for knowledge-enhanced responses and have extensively worked on Vision-Language Models (VLMs) for document understanding and data extraction from unstructured sources.I am currently exploring the development of Multi-Modal Co-Pilots (MCP) and Agentic AI systems—AI agents capable of perceiving, reasoning, and acting in complex environments. I''m passionate about pushing the boundaries of AI to solve real-world challenges at the intersection of perception, language, and autonomy.','\n',char(10)),'2025-05-23 11:48:25',NULL,'');
