INSERT INTO notes VALUES('f7c16d4e-811a-435b-b736-1291d2380441','Supervised fine tuning paper',replace('Long-context fine-tuning surprisingly makes short-context tasks better, and a balanced mix works best. \n\nThe paper tests this using a long-context base with a 512K window, then fine-tunes on short or long data, and evaluates on standard short tasks.\n\nModels fine-tuned on long data score higher on many short benchmarks in general knowledge, math, and code.\n\nAttention, the part that decides what to read from the prompt, gets better at pulling the right spans and keeping focus over steps.\n\nThe feed-forward network, the part that stores internal facts, shows stronger and broader activations, so recalling facts improves.\n\nA key caveat appears when context and memory disagree, short-only models trust internal memory and hit 99.8%, long-only models over-trust the prompt and fall to 50%.\n\nThis shows a knowledge preference bias, long training favors context, short training favors internal parameters.\n\nMixing the two reduces that bias, and around a 50% blend helps math-style reasoning that needs https://search.app/iw6EU','\n',char(10)),'2025-09-26 19:54:49',NULL,'');
