INSERT INTO notes VALUES('9275b9e6-c759-4776-9ded-a0441bde76eb','https://docs.google.com/document/d/1JK1W0Xc7XO-6VA1ayEz_wnrRxbyoU8z64qWntI5D7_0/edit?tab=t.0',replace('# 1. Study the BiGram Language Model code provided in the module . Your objective is to implement word based bi-gram model.\012\012import requests\012import re\012from collections import defaultdict, Counter\012from nltk.util import bigrams\012from nltk.tokenize import word_tokenize\012import random\012import nltk\012import math\012from bs4 import BeautifulSoup\012import torch\012import torch.nn as nn\012import torch.optim as optim\012from torch.utils.data import DataLoader, TensorDataset\012import matplotlib.pyplot as plt\012\012# Download necessary NLTK resources\012nltk.download(''punkt'')\012nltk.download(''punkt_tab'')\012\012## Implement relative-frequencies approach (using python dictionary)\012\012class BigramLanguageModelRF:\012    def __init__(self):\012        """Initializes the model with unigram and bigram frequency counters."""\012        self.unigram_counts = Counter()  # Stores individual word frequencies\012        self.bigram_counts = defaultdict(Counter)  # Stores bigram (word pair) frequencies\012        self.vocab = set()  # Set of unique words in the dataset\012        self.bigram_probs = {}  # Stores computed bigram probabilities\012\012    def preprocess_text(self, text):\012        """Cleans and tokenizes text."""\012        text = re.sub(r''\s+'', '' '', text)  # Normalize whitespace\012        tokens = word_tokenize(text.lower())  # Convert text to lowercase and tokenize\012        return tokens\012\012    def train(self, text):\012        """Trains the model by computing unigram and bigram counts."""\012        tokens = self.preprocess_text(text)\012        self.vocab.update(tokens)  # Add tokens to vocabulary\012        self.unigram_counts.update(tokens)  # Count occurrences of individual words\012        for w1, w2 in bigrams(tokens):\012            self.bigram_counts[w1][w2] += 1  # Count occurrences of word pairs\012\012    def compute_bigram_probabilities(self):\012        """Computes relative frequencies for bigram probabilities."""\012        for w1, w2_counts in self.bigram_counts.items():\012            total_count = sum(w2_counts.values())  # Total occurrences of w1\012            # Compute conditional probability P(w2 | w1)\012            self.bigram_probs[w1] = {w2: count / total_count for w2, count in w2_counts.items()}\012\012    def generate_sequence(self, start_sequence, length=50):\012        """Generates a sequence starting from given words using bigram probabilities."""\012        tokens = self.preprocess_text(start_sequence)  # Preprocess input sequence\012        sequence = tokens[:]  # Copy input tokens to sequence\012\012        for _ in range(length - len(sequence)):\012            last_word = sequence[-1]  # Get last word in sequence\012\012            if last_word in self.bigram_probs:  # Check if we have bigram data for last word\012                possible_words, probabilities = zip(*self.bigram_probs[last_word].items())\012                next_word = random.choices(possible_words, weights=probabilities, k=1)[0]  # Sample next word\012            else:\012                # If no known bigram exists, fallback to random unigram selection\012                next_word = random.choice(list(self.vocab)) if self.vocab else "<UNK>"\012\012            sequence.append(next_word)  # Append selected word to sequence\012\012        return '' ''.join(sequence)  # Return the generated sequence as a string\012\012    def compute_perplexity(self, test_text):\012        """Computes the perplexity of a given test text."""\012        tokens = self.preprocess_text(test_text)\012        N = len(tokens)\012        log_prob_sum = 0\012        smoothing = 1e-6  # Additive smoothing to handle unseen bigrams\012\012        for w1, w2 in bigrams(tokens):\012            if w1 in self.bigram_probs and w2 in self.bigram_probs[w1]:\012                prob = self.bigram_probs[w1][w2]  # Use trained probability if available\012            else:\012                prob = smoothing  # Assign a small probability to unseen bigrams\012\012            log_prob_sum += math.log(prob)  # Accumulate log probabilities\012\012        perplexity = math.exp(-log_prob_sum / N)  # Compute final perplexity score\012        return perplexity\012\012## Implement embeddings approach (using py-torch)\012\012# Import required libraries\012import torch\012import torch.nn as nn\012import torch.optim as optim\012import torch.nn.functional as F\012from torch.utils.data import DataLoader, TensorDataset\012import re\012import math\012from collections import Counter\012from nltk.tokenize import word_tokenize\012from nltk.util import bigrams\012\012\012# Define Bigram Language Model using Embeddings and Linear Layer\012class BigramLanguageModelEM(nn.Module):\012    def __init__(self, vocab_size, embed_dim):\012        """\012        Initializes the Bigram Language Model using Embeddings and a Linear Layer.\012\012        Parameters:\012        - vocab_size (int): Total number of unique words in vocabulary.\012        - embed_dim (int): Dimensionality of word embeddings.\012\012        The model consists of:\012        - An embedding layer (`nn.Embedding`) that converts word indices into dense vector representations.\012        - A linear layer (`nn.Linear`) that maps the embeddings to vocabulary space for word prediction.\012        """\012        super(BigramLanguageModelEM, self).__init__()\012\012        # Embedding layer: Maps words to dense vector representations\012        self.embeddings = nn.Embedding(vocab_size, embed_dim)\012\012        # Linear layer: Predicts the next word based on embedding\012        self.linear = nn.Linear(embed_dim, vocab_size)\012\012        # Xavier initialization for better weight distribution and stable training\012        nn.init.xavier_uniform_(self.embeddings.weight)\012        nn.init.xavier_uniform_(self.linear.weight)\012\012    def forward(self, x):\012        """\012        Forward pass of the model.\012\012        Parameters:\012        - x (Tensor): Input tensor containing word indices.\012\012        Returns:\012        - out (Tensor): Logits for the next word predictions.\012        """\012        embeds = self.embeddings(x)  # Convert input tokens to embeddings\012        out = self.linear(embeds)  # Compute logits for next word prediction\012        return out\012\012\012# Trainer class to handle training, evaluation, and text generation\012class BigramTrainerEM:\012    def __init__(self, embed_dim=10, learning_rate=0.001, epochs=30, batch_size=512):\012        """\012        Initializes the trainer for training and evaluating the Bigram Model.\012\012        Parameters:\012        - embed_dim (int): Size of word embeddings.\012        - learning_rate (float): Learning rate for optimizer.\012        - epochs (int): Number of training iterations.\012        - batch_size (int): Size of batches during training.\012        """\012        self.unigram_counts = Counter()  # Dictionary to store word frequencies\012        self.bigrams = []  # List to store bigram word pairs\012        self.vocab = {}  # Dictionary mapping words to unique indices\012        self.embed_dim = embed_dim  # Embedding dimension\012        self.learning_rate = learning_rate  # Learning rate for training\012        self.epochs = epochs  # Number of training epochs\012        self.batch_size = batch_size  # Batch size for model training\012        self.loss = []  # List to store loss values during training\012\012        # Detect GPU and enable CUDA if available for faster training\012        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")\012        print(f"Using device: {self.device}")\012\012    def preprocess_text(self, text):\012        """\012        Preprocesses the input text: removes extra spaces and tokenizes it.\012\012        Parameters:\012        - text (str): Raw input text.\012\012        Returns:\012        - tokens (list): List of cleaned and tokenized words.\012        """\012        text = re.sub(r''\s+'', '' '', text)  # Remove multiple spaces\012        tokens = word_tokenize(text.lower())  # Convert to lowercase and tokenize\012        return tokens\012\012    def train(self, text, save_path="bigram_model.pth"):\012        """\012        Trains the Bigram model using the provided text.\012\012        Parameters:\012        - text (str): Input training data.\012        - save_path (str): File path to save the trained model.\012        """\012        tokens = self.preprocess_text(text)  # Tokenize the input text\012        self.unigram_counts.update(tokens)  # Count word occurrences\012\012        # Create a vocabulary mapping words to unique indices\012        self.vocab = {word: idx for idx, word in enumerate(self.unigram_counts.keys())}\012\012        # Create bigram pairs and store their indices\012        self.bigrams = [(self.vocab[w1], self.vocab[w2]) for w1, w2 in bigrams(tokens) if w1 in self.vocab and w2 in self.vocab]\012\012        vocab_size = len(self.vocab)  # Get vocabulary size\012        self.model = BigramLanguageModelEM(vocab_size, self.embed_dim).to(self.device)  # Initialize model\012        criterion = nn.CrossEntropyLoss()  # Loss function for classification\012        optimizer = optim.Adam(self.model.parameters(), lr=self.learning_rate)  # Adam optimizer\012\012        # Check if there are no valid bigrams\012        if not self.bigrams:\012            print("No bigrams found. Training skipped.")\012            return\012\012        # Convert bigram data into tensors\012        inputs, targets = zip(*self.bigrams)\012        inputs = torch.tensor(inputs, dtype=torch.long)\012        targets = torch.tensor(targets, dtype=torch.long)\012        dataset = TensorDataset(inputs, targets)\012        data_loader = DataLoader(dataset, batch_size=self.batch_size, shuffle=True)\012\012        scaler = torch.cuda.amp.GradScaler()  # Enable mixed precision training for better efficiency\012\012        # Training loop\012        for epoch in range(self.epochs):\012            epoch_loss = 0.0\012            for batch_inputs, batch_targets in data_loader:\012                batch_inputs, batch_targets = batch_inputs.to(self.device), batch_targets.to(self.device)\012\012                optimizer.zero_grad()\012                outputs = self.model(batch_inputs)  # Forward pass\012                loss = criterion(outputs, batch_targets)  # Compute loss\012\012                scaler.scale(loss).backward()  # Backpropagation with scaling\012                scaler.step(optimizer)  # Update model parameters\012                scaler.update()\012\012                epoch_loss += loss.item()\012\012            self.loss.append(epoch_loss / len(data_loader))\012            print(f"Epoch {epoch+1}/{self.epochs}, Loss: {epoch_loss / len(data_loader):.4f}")\012\012        # Save the trained model\012        torch.save({"model_state_dict": self.model.state_dict(),\012                    "vocab": self.vocab,\012                    "embed_dim": self.embed_dim}, save_path)\012        print(f"Model saved to {save_path}")\012\012    def generate_sequence(self, start_words, length=50, temperature=1.0):\012        """\012        Generates a text sequence based on a given start phrase.\012\012        Parameters:\012        - start_words (str): Initial text to begin generation.\012        - length (int): Number of words to generate.\012        - temperature (float): Controls randomness in predictions.\012\012        Returns:\012        - str: Generated text sequence.\012        """\012        tokens = self.preprocess_text(start_words)  # Tokenize input\012        sequence = []\012\012        # Convert input words to indices\012        input_indices = [self.vocab[word] for word in tokens if word in self.vocab]\012        if not input_indices:\012            return "All start words are unknown."\012\012        sequence.extend(tokens)  # Store input words in sequence\012        current_indices = input_indices[:]\012\012        for _ in range(length - len(sequence)):\012            input_tensor = torch.tensor([current_indices[-1]], dtype=torch.long).to(self.device)\012            with torch.no_grad():\012                output = self.model(input_tensor)  # Predict next word logits\012                output = output / temperature  # Apply temperature scaling\012                probs = torch.softmax(output, dim=-1)  # Convert logits to probabilities\012\012            predicted_idx = torch.multinomial(probs[0], num_samples=1).item()  # Sample next word\012            if predicted_idx not in self.vocab.values():\012                break  # Stop if no valid next word\012\012            next_word = [word for word, idx in self.vocab.items() if idx == predicted_idx][0]\012            sequence.append(next_word)\012            current_indices.append(predicted_idx)\012\012        return '' ''.join(sequence)\012\012    def compute_perplexity(self, test_text):\012        """\012        Computes the perplexity of the given text.\012\012        Parameters:\012        - test_text (str): Input text.\012\012        Returns:\012        - float: Perplexity score.\012        """\012        tokens = self.preprocess_text(test_text)\012        N = len(tokens)\012        log_prob_sum = 0\012        smoothing = 1e-6  # Small probability for unseen bigrams\012\012        if N < 2:\012            return float(''inf'')  # Avoid division by zero\012\012        with torch.no_grad():\012            for w1, w2 in bigrams(tokens):\012                prob = smoothing\012                log_prob_sum += math.log(prob)\012\012        perplexity = math.exp(-log_prob_sum / (N - 1))\012        return perplexity\012\012# 2. Apply your modelling approaches to train a language models that generates financial discourse in Warren Buffet''s style. Train you models using Warren Buffets''s Annual Letters to shareholders download Warren Buffets''s Annual Letters to shareholders\012\012You can restrict the vocabulary by applying appropriate transformations (lower-case, removal of numeric, dates data, removal of acronyms etc).\012\012## Data download and dataset preparation\012\012# def download_warren_buffett_letter(url, output_file):\012#     headers = {\012#         "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"\012#     }\012\012#     response = requests.get(url, headers=headers)\012#     response.raise_for_status()  # Ensure we notice bad responses\012\012#     soup = BeautifulSoup(response.text, ''html.parser'')\012\012#     # Extract text from the webpage and remove unwanted headers\012#     text_content = soup.get_text()\012\012#     # Find the start of actual letter content\012#     start_idx = text_content.find("Chairman''s Letter")\012#     if start_idx != -1:\012#         text_content = text_content[start_idx:]  # Trim unwanted text before letter\012\012#     # Save content to a text file\012#     with open(output_file, ''a'', encoding=''utf-8'') as file:\012#         file.write("\n" + text_content)\012\012# years = [\012#     1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986,\012#     1987, 1988, 1989, 1990, 1991, 1992, 1993, 1994, 1995, 1996,\012#     1997, 1998, 1999, 2000, 2001, 2002, 2003, 2004, 2005, 2006\012# ]\012\012# # Download and save\012# output_filename = "Warren_Buffett_Letters.txt"\012# for year in years:\012#     download_url = "https://www.berkshirehathaway.com/letters/" + str(year) + ".html"\012#     print(download_url)\012#     download_warren_buffett_letter(download_url, output_filename)\012\012# print(f"Downloaded content saved to {output_filename}")\012\012\012# def preprocess_text(text):\012#     # Convert to lowercase\012#     text = text.lower()\012\012#     # Define crucial financial terms\012#     financial_terms = {"revenue", "profit", "loss", "earnings", "eps", "dividend", "margin",\012#                        "growth", "pe", "valuation", "market", "cap", "shares", "stock", "index",\012#                        "price", "volume", "ratio", "q", "fy"}  # "Q" for quarters, "FY" for fiscal years\012\012#     # Remove common date formats (YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY)\012#     text = re.sub(r''\b\d{4}-\d{2}-\d{2}\b'', '''', text)  # YYYY-MM-DD\012#     text = re.sub(r''\b\d{2}/\d{2}/\d{4}\b'', '''', text)  # DD/MM/YYYY or MM/DD/YYYY\012\012#     # Keep only financial terms, numbers, and dollar signs\012#     words = text.split()\012#     cleaned_words = [\012#         word if word in financial_terms or re.search(r''[\d$]'', word) or re.search(r''[a-zA-Z]'', word) else ''''\012#         for word in words\012#     ]\012#     text = '' ''.join(cleaned_words)\012\012#     # Remove acronyms (all caps words, but keep financial terms)\012#     text = '' ''.join([word if not word.isupper() or word in financial_terms else '''' for word in text.split()])\012\012#     # Remove special characters (except $ and spaces)\012#     text = re.sub(r''[^\w\s$]'', '''', text)\012\012#     # Remove extra spaces\012#     text = re.sub(r''\s+'', '' '', text).strip()\012\012#     return text\012\012# def process_text_file(file_path):\012#     try:\012#         with open(file_path, ''r'', encoding=''utf-8'') as file:\012#             text = file.read()\012#             processed_text = preprocess_text(text)\012#             return processed_text\012#     except FileNotFoundError:\012#         return "File not found."\012#     except Exception as e:\012#         return f"An error occurred: {e}"\012\012# file_path = "Warren_Buffett_Letters.txt"  # Replace with your file path\012# processed_text = process_text_file(file_path)\012# # print(processed_text)\012\012# output_file_processed = "Warren_Buffett_Letters_processed.txt"\012# with open(output_file_processed, ''w'', encoding=''utf-8'') as file:\012#         file.write("\n" + processed_text)\012\012## Evaluate performance of each model in terms of model perplexity\012\012# Define the file path for the text file containing Warren Buffett''s letters\012file_path = "Warren_Buffett_Letters_processed.txt"\012\012# Open the file in read mode with UTF-8 encoding\012with open(file_path, ''r'', encoding=''utf-8'') as file:\012    # Read the entire content of the file into a string variable\012    text = file.read()\012\012\012### Relative-frequencies approach\012\012# Example usage of the Bigram Language Model with Relative Frequency (RF)\012\012# A sample test sentence for evaluation\012# test_text = "revenue growth is strong but market remains uncertain"\012test_text = "Shareholder is"\012\012# Instantiate the bigram language model\012model = BigramLanguageModelRF()\012\012# Train the model using the provided text (assumed to be loaded from a file earlier)\012model.train(text)\012\012# Compute bigram probabilities using relative frequency\012model.compute_bigram_probabilities()\012\012# Compute the perplexity of the test sentence\012pp = model.compute_perplexity(test_text)\012\012# Generate a sequence based on the test text as input\012print(model.generate_sequence(test_text))\012\012# Print the computed perplexity value\012print(f"Perplexity: {pp}")\012\012# Define a list of prompts to generate text sequences\012prompts = [\012    "Capital allocation",\012    "volatility in ",\012    "Long term",\012    "Shareholders should",\012    "The stock market",\012    "sustainable competitive ",\012    "A strong management",\012    "Business management",\012    "The true investor",\012    "Compound interest"\012]\012\012# Initialize an empty list to store the output results\012output = []\012\012# Iterate through each prompt and generate text sequences\012for prompt in prompts:\012    # Generate a text sequence based on the given prompt\012    Generated_Sequence = model.generate_sequence(prompt)\012\012    # Compute the perplexity score for the generated sequence\012    perplexity = model.compute_perplexity(prompt)\012\012    # Store the results as a list [Prompt, Generated_Sequence, Perplexity]\012    output.append([prompt, Generated_Sequence, perplexity])\012\012# Import Pandas for handling data in tabular format\012import pandas as pd\012\012# Create a DataFrame to store the results\012bigrammodelRF_df = pd.DataFrame(output, columns=[''Prompt'', ''Generated_Sequence'', ''Perplexity''])\012\012# Save the DataFrame to a CSV file for further analysis\012bigrammodelRF_df.to_csv(''bigrammodelRF_df.csv'', index=False)\012\012# Display the DataFrame\012bigrammodelRF_df\012\012### Embeddings approach\012\012# Ensuring the script runs only when executed directly, not when imported\012if __name__ == "__main__":\012\012    # Define the file path for the text file containing Warren Buffett''s letters\012    file_path = "Warren_Buffett_Letters_processed.txt"\012\012    # Open and read the file content into a string variable\012    with open(file_path, ''r'', encoding=''utf-8'') as file:\012        text = file.read()\012\012    # Initialize the BigramTrainerEM model with specific hyperparameters\012    trainer = BigramTrainerEM(embed_dim=256, learning_rate=0.001, epochs=100, batch_size=512)\012\012    # Train the model on the loaded text and save the trained model to a file\012    trainer.train(text, save_path="bigrammodelEM.pth")\012\012# Plot the loss curve\012plt.plot(trainer.loss)\012\012# Add labels and title\012plt.xlabel("Epochs")\012plt.ylabel("Loss")\012plt.title("Training Loss Curve")\012\012# Show the plot\012plt.show()\012\012# Generate a text sequence using the trained Bigram model\012print("\nGenerated Sequence:", trainer.generate_sequence("fiscal year", length=50, te','\012',char(10)),'2025-04-17 17:51:42',NULL,'');
