INSERT INTO notes VALUES('906c070c-6d56-4586-b57f-02354dd58792','',replace('Hello sir\nOur convocation is planned on 21st November. Actually I am planning to go to Jodhpur on 20th November and will return on 22nd November and planning to book the ticket for the same. Could you please confirm sir can I take leave for 2 days and 1 day work from home sir on 22nd November. \n\n\nCertainly, here''s your request with a more direct tone:\n\nHello sir,\n\nI''d like to inform you that my convocation is scheduled for 21st November, and I''m planning to be in Jodhpur from 20th to 22nd November. I kindly request your approval for a two-day leave on the 20th and 21st, and I would like to work from home on the 22nd to ensure a smooth workflow. Your confirmation for this arrangement would be greatly appreciated. Thank you.','\n',char(10)),'2023-11-04 21:56:29',NULL,'');
