INSERT INTO notes VALUES('297c2283-d6f0-452d-b914-841794049cbc','',replace('https://colab.research.google.com/github/tensorflow/docs/blob/snapshot-keras/site/en/guide/keras/sequential_model.ipynb#scrollTo=1368bd27f679\n\nmodel = keras.Sequential(\n    [\n        layers.Dense(2, activation="relu"),\n        layers.Dense(3, activation="relu"),\n        layers.Dense(4),\n    ]\n)  # No weights at this stage!\n\n# At this point, you can''t do this:\n# model.weights\n\n# You also can''t do this:\n# model.summary()\n\n# Call the model on a test input\nx = tf.ones((1, 4))\ny = model(x)\nmodel.summary()\nprint("Number of weights after calling the model:", len(model.weights))  # 6\n\nprint(x)\n\noutput:\ntf.Tensor([[1. 1. 1. 1.]], shape=(1, 4), dtype=float32)\n\nmodel.summary()\n# Tensor size 4 \n# Tensor_size * no_of_neurons(weights associated) + no_of_neurons (bias associated)\n# 4 * 2 + 2 = 10\n# 2 * 3 + 3 = 9\n# 3 * 4 + 4 = 16\n\noutput:\nModel: "sequential_3"\n_________________________________________________________________\n Layer (type)                Output Shape              Param #   \n=================================================================\n dense_7 (Dense)             (1, 2)                    10        \n                                                                 \n dense_8 (Dense)             (1, 3)                    9         \n                                                                 \n dense_9 (Dense)             (1, 4)                    16        \n                                                                 \n=================================================================\nTotal params: 35\nTrainable params: 35\nNon-trainable params: 0\n_________________________________________________________________','\n',char(10)),'2023-02-22 16:10:30',NULL,'');
