INSERT INTO notes VALUES('54f154b7-0348-42ee-be96-29762050e906','LLMs are naturally interleaved multimodal creators',replace('The paper’s big idea is, let the language model act like a planner and pick the right image tool for each step.\n\nIt outperforms prior systems on several benchmarks and even hits 100% tool accuracy on a tough internal set.\n\nUnified models try to do everything with one generator, so they fail on real photos, exact charts, or precise edits.\n\n LLM-Interleaved (LLM-I), fixes this by making the model write the report, insert small tags where an image should go, then a parser runs the right tool and drops the image back in. \n\nThe toolset is 4 parts, web search for real pictures, diffusion for creative images, code execution for charts, and image editing.\n\nTraining uses reinforcement learning with 3 rewards, rules that check tag format and image count, a language judge for writing and tool choice, and a multimodal judge that scores the final text plus images.\n\nA key twist, the visual judge score only counts if the rules are met, so the model learns to obey image constraints before chasing pret https://search.app/YKJvS','\n',char(10)),'2025-09-21 21:49:57',NULL,'');
